import 'package:flutter/material.dart';
import 'package:pooja_sindhu/core/theme/app_colors.dart';
import 'package:pooja_sindhu/features/booking/domain/entities/booking_status.dart';
class StatusBadge extends StatelessWidget { const StatusBadge({super.key, required this.status}); final BookingStatus status; @override Widget build(BuildContext context) { final value = switch (status) { BookingStatus.draft => ('Draft', AppColors.textSecondary), BookingStatus.pendingPayment => ('Pending Payment', AppColors.warning), BookingStatus.confirmed => ('Confirmed', AppColors.success), BookingStatus.paymentFailed => ('Payment Failed', AppColors.error), BookingStatus.cancelled => ('Cancelled', AppColors.error), BookingStatus.completed => ('Completed', AppColors.info) }; return Container(padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4), decoration: BoxDecoration(color: value.$2.withOpacity(.12), borderRadius: BorderRadius.circular(4)), child: Text(value.$1, style: TextStyle(color: value.$2, fontSize: 12, fontWeight: FontWeight.w600))); } }
